import { CreateEventTicket } from '@domain/events';
import { PublicActionPageFieldConfiguration } from '@domain/publicActionPage';
import { ChangeEvent, ChangeEventHandler, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { InputControl } from 'src/builder/PublicActionPage/components/InputControl';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';
import { RadioControl, RadioGroup } from 'src/builder/PublicActionPage/components/RadioButtonGroup';
import { SelectControl } from 'src/builder/PublicActionPage/components/SelectControl';

type Props = {
  currentlyEmployedFieldName: string;
  employerNameFieldName: string;
  fieldConfiguration: PublicActionPageFieldConfiguration;
  occupationFieldName: string;
  occupationOptions?: string[];
  onBlur?:
    | ((e?: ChangeEvent<HTMLSelectElement | HTMLInputElement>) => void)
    | ChangeEventHandler<HTMLSelectElement | HTMLInputElement>;
  onChange:
    | ((e: ChangeEvent<HTMLSelectElement | HTMLInputElement>) => void)
    | ChangeEventHandler<HTMLSelectElement | HTMLInputElement>;
  onCurrentlyEmployedChange: (value: boolean | string) => void;
  ticketDetails: Omit<CreateEventTicket, 'addressAttributes' | 'price' | 'ticketTypeId'>;
};

export const AttendeeEmployment = ({
  currentlyEmployedFieldName,
  employerNameFieldName,
  fieldConfiguration,
  occupationFieldName,
  occupationOptions,
  onBlur,
  onChange,
  onCurrentlyEmployedChange,
  ticketDetails,
}: Props) => {
  const { t } = useTranslation(['common', 'actionPagesBuilder', 'customFields']);

  const {
    displayEmployment,
    includeEmployerName,
    includeOccupation,
    occupationHelpText,
    occupationLabel: occupationLabelOption,
  } = fieldConfiguration || {};

  const occupationLabel = useMemo(
    () =>
      occupationLabelOption
        ? t(`customFields:employment.occupationLabels.${occupationLabelOption}`)
        : t('customFields:employment.occupationLabels.occupationLabel'),
    [occupationLabelOption, t]
  );

  const nonEmployedOptions = useMemo(
    () => [
      {
        label: t('customFields:employment.unemployedOptions.homemaker'),
        value: 'homemaker',
      },
      {
        label: t('customFields:employment.unemployedOptions.retired'),
        value: 'retired',
      },
      {
        label: t('customFields:employment.unemployedOptions.student'),
        value: 'student',
      },
      {
        label: t('customFields:employment.unemployedOptions.unemployed'),
        value: 'unemployed',
      },
    ],
    [t]
  );

  return (
    <div className="flex w-full gap-2">
      <div className="flex grow">
        <div className="mt-2 flex w-full flex-col gap-2">
          {displayEmployment ? (
            <RadioGroup
              formControlProps={{
                className: '!mb-0',
              }}
              label={t('customFields:employment.areYouEmployed')}
              name={currentlyEmployedFieldName}
              onChange={onCurrentlyEmployedChange}
              value={ticketDetails.currentlyEmployed}
            >
              <div className="flex gap-4">
                <div className="mt-1">
                  <RadioControl key="yes" value="true">
                    {t('common:yes')}
                  </RadioControl>
                </div>
                <div className="mt-1">
                  <RadioControl key="no" value="false">
                    {t('common:no')}
                  </RadioControl>
                </div>
              </div>
            </RadioGroup>
          ) : null}
          {ticketDetails.currentlyEmployed ? (
            <>
              <div className="@md:flex-row flex flex-col gap-2 md:flex-row">
                {includeEmployerName ? (
                  <InputControl
                    formControlProps={{ className: 'my-0 !mb-0' }}
                    label={t('customFields:employment.employerName')}
                    name={employerNameFieldName}
                    onBlur={onBlur}
                    onChange={onChange as (e: unknown) => void}
                    value={ticketDetails.employerName}
                  />
                ) : null}
                {includeOccupation ? (
                  occupationOptions?.length && occupationOptions?.length > 0 ? (
                    <SelectControl
                      defaultValue="retired"
                      formControlProps={{ className: 'my-0 !mb-0' }}
                      label={occupationLabel || t('customFields:employment.occupation')}
                      name={occupationFieldName}
                      onBlur={onBlur}
                      onChange={onChange}
                      options={occupationOptions.map((o) => ({ label: o, value: o }))}
                      value={ticketDetails.occupation}
                    />
                  ) : (
                    <InputControl
                      formControlProps={{ className: 'my-0 !mb-0' }}
                      label={occupationLabel || t('customFields:employment.occupation')}
                      name={occupationFieldName}
                      onBlur={onBlur}
                      onChange={onChange as (e: unknown) => void}
                      value={ticketDetails.occupation}
                    />
                  )
                ) : null}
              </div>
              {includeOccupation && occupationHelpText && <Meta>{occupationHelpText}</Meta>}
            </>
          ) : includeOccupation && nonEmployedOptions.length ? (
            <SelectControl
              defaultValue="retired"
              formControlProps={{
                className: 'my-0 !mb-0',
              }}
              label={occupationLabel || t('customFields:employment.occupation')}
              name={occupationFieldName}
              onBlur={onBlur}
              onChange={onChange}
              options={nonEmployedOptions}
              value={ticketDetails.occupation}
            />
          ) : null}
        </div>
      </div>
    </div>
  );
};

